import React, { useState, createContext, useContext } from 'react';

interface ThemeContent {
	themeSelected: string;
	themeBgClassName: string;
	themeTextClassName: string;
	movieProfileTheme: string;
	movieProfileHoverTheme: string;
}

interface ThemeOptions {
	night: ThemeContent;
	light: ThemeContent
}

interface ThemeContextProps {
	theme: ThemeContent;
	toggleTheme: () => void;
}

const themeOption = {
	night: {
		themeSelected: 'night',
		themeBgClassName: 'bg-slate-900',
		themeTextClassName: 'text-white',
		movieProfileTheme: 'bg-slate-800',
		movieProfileHoverTheme: 'bg-slate-700'
	},
	light: {
		themeSelected: 'light',
		themeBgClassName: 'bg-slate-100',
		themeTextClassName: 'text-slate-800',
		movieProfileTheme: 'bg-slate-300',
		movieProfileHoverTheme: 'bg-slate-400'
	}
};
// const nightMode = {themeOption: 'night', themeBgClassName: 'bg-slate-900', themeTextClassName: 'text-white', movieProfileTheme: 'bg-slate-800', movieProfileHoverTheme: 'bg-slate-700'};
// const lightMode = {themeOption: 'light', themeBgClassName: 'bg-slate-100', themeTextClassName: 'text-slate-800', movieProfileTheme: 'bg-slate-300', movieProfileHoverTheme: 'bg-slate-400'};

export const ThemeContext = createContext<ThemeContextProps>({} as ThemeContextProps);

export default function ThemeContextProvider({ children }: any) {
	const [theme, setTheme] = useState<ThemeContent>(themeOption[getThemeFromLocalStorage()]);

	const toggleTheme = () => {
		setTheme(theme => (theme.themeSelected === 'light' ? themeOption.light : themeOption.night));
		localStorage.setItem('dmdb-theme', theme.themeSelected);
	};

	return <ThemeContext.Provider value={{ theme, toggleTheme }}>{children}</ThemeContext.Provider>;
}

export function useTheme() {
	const { theme, toggleTheme } = useContext(ThemeContext);
	return { theme, toggleTheme };
}

function getThemeFromLocalStorage() {
	const theme = localStorage.getItem('dmdb-theme');

	if (theme && (theme === 'light' || theme === 'night')) {
		return theme;
	}

	return 'night';
}

